test_cases.assertion_pseudocode:
// scenario 1
result, err = resolveHubURL(flag="https://flag.example.com", env="https://env.example.com", cfg.HubURL="https://config.example.com")
assert err == nil AND result == "https://flag.example.com"
// scenario 2
result, err = resolveHubURL(flag="", env="https://env.example.com", cfg.HubURL="https://config.example.com")
assert err == nil AND result == "https://env.example.com"
// scenario 3
result, err = resolveHubURL(flag="", env="", cfg.HubURL="https://config.example.com")
assert err == nil AND result == "https://config.example.com"
// scenario 4
result, err = resolveHubURL(flag="", env="", cfg.HubURL="")
assert err != nil

// scenario 1
result, err = resolveAPIKey(flag="af_flagtoken", env="af_envtoken", cfg=cfg)
assert err == nil AND result == "af_flagtoken"
// scenario 2
result, err = resolveAPIKey(flag="", env="af_envtoken", cfg=cfg)
assert err == nil AND result == "af_envtoken"
// scenario 3
result, err = resolveAPIKey(flag="", env="", cfg=cfg) // cfg.APIKey="my-project", cfg.Keys["my-project"].Token="af_abc_secret"
assert err == nil AND result == "af_abc_secret"
// scenario 4
result, err = resolveAPIKey(flag="", env="", cfg=emptyConfig)
assert err != nil

property_tests.invariant_check:
for all (flag, env, cfg_hub_url) where flag != "" OR env != "":
  result, err = resolveHubURL(flag=flag, env=env, cfg.HubURL=cfg_hub_url)
  assert err == nil
  if flag != "":
    assert result == flag
  else:
    assert result == env
  assert result != cfg_hub_url OR result == flag OR result == env  // config value never wins when flag/env set

for any mutation M applied to config C:
  // Read config.toml at any point during M
  snapshot = readFileAtRandomPoint(homeDir + "/.af/config.toml")
  // Snapshot must be parseable as valid TOML (either old or new state)
  _, err = toml.Decode(snapshot)
  assert err == nil
  // File size must equal either old content size or new content size
  assert len(snapshot) == len(oldContent) OR len(snapshot) == len(newContent)

for any cfg where cfg.HubURL == "":
  if flag == "" AND env == "":
    result, err = resolveHubURL(flag="", env="", cfg=cfg)
    assert result == "" AND err != nil  // error, not empty success
  if flag != "":
    result, err = resolveHubURL(flag=flag, env="", cfg=cfg)
    assert result == flag AND err == nil
for any cfg where cfg.APIKey == "":
  if flag == "" AND env == "":
    result, err = resolveAPIKey(flag="", env="", cfg=cfg)
    assert err != nil
